SELECT count(*) FROM title, movie_keyword, keyword, movie_info, kind_type, info_type, cast_info, role_type WHERE movie_keyword.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND movie_info.movie_id = title.id AND title.kind_id = kind_type.id AND movie_info.info_type_id = info_type.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id;